import React from 'react';

function Parallax({ scrollPercentage, speed }) {
    return (
      <div className="Parallax">
        <div className="Layer1" style={{backgroundImage: `url('/pics/Layer4.webp')`, backgroundPositionX: `calc(-${scrollPercentage * 0.5 * speed}% + 0px)`}}></div>
        <div className="Layer2" style={{backgroundImage: `url('/pics/Layer3.webp')`, backgroundPositionX: `calc(-${scrollPercentage * 0.4 * speed}px + 100px)`}}></div>
        <div className="Layer3" style={{backgroundImage: `url('/pics/Layer2.webp')`, backgroundPositionX: `calc(-${scrollPercentage * -0.6 * speed}px + 100px)`}}></div>
        <div className="Layer4" style={{backgroundImage: `url('/pics/Layer1.webp')`, backgroundPositionX: `calc(-${scrollPercentage * 0.8 * speed}px + 100px)`}}></div>
        <div className="Layer5" style={{backgroundImage: `url('/pics/Layer0.webp')`, backgroundPositionX: `calc(-${scrollPercentage * -1.0 * speed}px - 3000px)`}}></div>
      </div>
    );
  }
  

export default Parallax;
